class Solution:
    def minNumber(self, nums1, nums2):
        candidates = []
        for d in range(1, 10):
            if d in nums1 and d in nums2:
                candidates.append(d)
        if candidates:
            return min(candidates)
        for d1 in nums1:
            for d2 in nums2:
                lo, hi = (d1, d2) if d1 < d2 else (d2, d1)
                candidates.append(lo * 10 + hi)
        return min(candidates)

