class Solution:
    def minNumber(self, nums1, nums2):
        common = set(nums1) & set(nums2)
        if common:
            return min(common)
        a, b = min(nums1), min(nums2)
        lo, hi = (a, b) if a < b else (b, a)
        return lo * 10 + hi

